sys_variable_value.value:
(function execute(inputs, outputs) {

	var actionDetails, actionResults, actionStatus;
	var actionUtil = new x_taniu_tan_core.TaniumActionUtil();
	var actionID = inputs['tan_action_id'];
	var completedCount = 0;

	if (!actionID) {
		throw new Error(
			'Attempted to get status of Tanium Action but a valid action ID was not specified.'
		);
	}

	actionDetails = actionUtil.getActionDetailsByID(actionID);

	if (
		!actionDetails ||
		!actionDetails.hasOwnProperty('data') ||
		!actionDetails.data.hasOwnProperty('status')
	) {
		throw new Error(
			'Attempted to get status of Tanium Action but a valid action ID was not ' +
			'specified or found in Tanium.'
		);
	}

	actionStatus = actionDetails.data.status.toString();

	outputs['tan_action_status'] = actionStatus;
	outputs['tan_action_details'] = actionDetails;

	actionResults = actionUtil.getActionResultsByID(actionID);
	actionResults = actionResults.data.result_sets[0];
	completedCount = getCompletedCount(actionResults);

	outputs['tan_endpoints_completed'] = completedCount;

	//HELPER FUNCTIONS BELOW

	function getCompletedCount(actionResults) {
		var i, statusRows;
		var completedCount = 0;
		var resultsColumnIndex = getStatusColumnIndex(actionResults);

		if (resultsColumnIndex === false) {
			return 0;
		}

		statusRows = actionResults.rows;
		for (i = 0; i < statusRows.length; i++) {
			if (statusRows[i].data[resultsColumnIndex][0].text.indexOf('Completed') >= 0) {
				completedCount++;
			}
		}

		return completedCount;
	}

	function getStatusColumnIndex(actionResults) {
		var i;

		for (i = 0; i < actionResults.columns.length; i++) {
			if (actionResults.columns[i].name == 'Action Statuses') {
				return i;
			}
		}

		//Unable to find results column
		return false;
	}

})(inputs, outputs);

